CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;

CREATE TABLE "Admins" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Usuario" text NOT NULL,
    "SenhaHash" text NOT NULL,
    CONSTRAINT "PK_Admins" PRIMARY KEY ("Id")
);

CREATE TABLE "Quilombos" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Codigo" integer NOT NULL,
    "Nome" text NOT NULL,
    "Regiao" text,
    "Municipio" text,
    CONSTRAINT "PK_Quilombos" PRIMARY KEY ("Id")
);

CREATE TABLE "Postagens" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "QuilomboId" integer NOT NULL,
    "Titulo" text NOT NULL,
    "Subtitulo" text,
    "Texto" text NOT NULL,
    "DataHora" timestamp with time zone NOT NULL,
    "ImagemHeaderPath" text,
    CONSTRAINT "PK_Postagens" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Postagens_Quilombos_QuilomboId" FOREIGN KEY ("QuilomboId") REFERENCES "Quilombos" ("Id") ON DELETE CASCADE
);

CREATE TABLE "Comentarios" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "PostagemId" integer NOT NULL,
    "Nome" text NOT NULL,
    "Texto" text NOT NULL,
    "DataHora" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_Comentarios" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Comentarios_Postagens_PostagemId" FOREIGN KEY ("PostagemId") REFERENCES "Postagens" ("Id") ON DELETE CASCADE
);

CREATE TABLE "ImagensPostagem" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "PostagemId" integer NOT NULL,
    "Path" text NOT NULL,
    "NomeOriginal" text,
    "Ordem" integer NOT NULL,
    CONSTRAINT "PK_ImagensPostagem" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_ImagensPostagem_Postagens_PostagemId" FOREIGN KEY ("PostagemId") REFERENCES "Postagens" ("Id") ON DELETE CASCADE
);

