CREATE UNIQUE INDEX "IX_Admins_Usuario" ON "Admins" ("Usuario");

CREATE INDEX "IX_Comentarios_PostagemId" ON "Comentarios" ("PostagemId");

CREATE INDEX "IX_ImagensPostagem_PostagemId" ON "ImagensPostagem" ("PostagemId");

CREATE INDEX "IX_Postagens_QuilomboId" ON "Postagens" ("QuilomboId");

CREATE UNIQUE INDEX "IX_Quilombos_Codigo" ON "Quilombos" ("Codigo");

SELECT setval(
    pg_get_serial_sequence('"Admins"', 'Id'),
    GREATEST(
        (SELECT MAX("Id") FROM "Admins") + 1,
        nextval(pg_get_serial_sequence('"Admins"', 'Id'))),
    false);
SELECT setval(
    pg_get_serial_sequence('"Quilombos"', 'Id'),
    GREATEST(
        (SELECT MAX("Id") FROM "Quilombos") + 1,
        nextval(pg_get_serial_sequence('"Quilombos"', 'Id'))),
    false);

